```ts
// BAD: 100 docs × 200 ms each = 20 s
for (const d of docs) results.push(await embed(d))
// GOOD: max ≈ 200 ms (server-side concurrency)
const results = await Promise.all(docs.map(embed))
```

```ts
// BAD: unhandled rejection — process may crash
const data = await fetch('/x').then(r => r.json())
// GOOD
try { const data = await fetch('/x').then(r => r.json()) }
catch (e) { handle(e) }
```

```ts
// BAD: one bad URL kills all 100 results
const results = await Promise.all(urls.map(fetch))
// GOOD: each result has { status, value | reason }
const settled = await Promise.allSettled(urls.map(fetch))
```
